#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long A,B,M; scanf("%lld %lld %lld",&A,&B,&M);
        long long diff = llabs(A-B);
        long long ans = diff < M-diff ? diff : M-diff;
        printf("%lld",ans);
        if(T) printf("\n");
    }
    return 0;
}

